// filteredArticles配列を個別アイテムに展開
const articles = items[0].json.filteredArticles || items;
if (Array.isArray(articles) && articles.length > 0 && articles[0].json) {
  return articles;
}
return (Array.isArray(articles) ? articles : [articles]).map(a => ({ json: a }));

const responseText = items[0].json.candidates[0].content.parts[0].text;
const originalArticle = $('記事生成プロンプト作成').first().json;
const today = originalArticle.today || new Date().toISOString().split('T')[0];

// front matter + markdownを整形
let articleContent = responseText.trim();

// --- で始まっていない場合に補正
if (!articleContent.startsWith('---')) {
  const yamlStart = articleContent.indexOf('---');
  if (yamlStart >= 0) articleContent = articleContent.substring(yamlStart);
}

// ファイル名を生成（タイトルからURLセーフな文字列を作成）
const titleMatch = articleContent.match(/title:\s*"?([^"\n]+)"?/);
const titleSlug = titleMatch
  ? titleMatch[1].replace(/[^a-zA-Z0-9\u3040-\u309F\u30A0-\u30FF\u4E00-\u9FAF]/g, '-').substring(0, 50)
  : 'article';
const filename = `${today}-${Date.now()}.md`;

console.log(`記事生成完了: ${filename}`);

return [{
  json: {
    filename,
    content: articleContent,
    originalTitle: originalArticle.title,
    sourceUrl: originalArticle.link,
    today
  }
}];
